import json
import pandas as pd

release_file = var_functions.query_db:26

with open(release_file, 'r') as f:
    releases_raw = json.load(f)

print(f"Total: {len(releases_raw)}")

packages = {}
for pkg in releases_raw:
    try:
        name = pkg['Name']
        version_info_raw = pkg['VersionInfoCompact']

        # Clean up the string
        clean_json = version_info_raw.replace('\n', '').strip()
        version_info = json.loads(clean_json)

        ordinal = version_info.get('Ordinal', 0)

        if name not in packages or ordinal > packages[name]['Ordinal']:
            packages[name] = {
                'Version': pkg['Version'],
                'Ordinal': ordinal
            }
    except Exception as e:
        continue

print(f"Latest releases: {len(packages)}")

latest_list = []
for name, info in packages.items():
    latest_list.append({
        'Name': name,
        'Version': info['Version']
    })

result = json.dumps(latest_list[:5])
print('__RESULT__:')
print(result)

