import json

pkg_file = var_functions.query_db:66
print('File path:', pkg_file)

with open(pkg_file, 'r') as f:
    packages = json.load(f)

print('Total packages:', len(packages))

# Find latest release for each package
latest = {}
for pkg in packages:
    name = pkg['Name']
    ver = pkg['Version']
    try:
        ver_info = json.loads(pkg['VersionInfo'].replace('\n', ' '))
        if ver_info.get('IsRelease'):
            ordinal = ver_info.get('Ordinal', 0)
            if name not in latest or ordinal > latest[name]['ordinal']:
                latest[name] = {'version': ver, 'ordinal': ordinal}
    except:
        pass

print('Latest releases found:', len(latest))
result = json.dumps([{'name': k, 'version': v['version']} for k, v in list(latest.items())[:10]])
print('__RESULT__:')
print(result)

